// Pure domain. No Spring, no JPA, no Jackson. Just business rules.
public final class Account {
    private final AccountId id;
    private Money balance;

    public Account(AccountId id, Money opening) {
        if (opening.isNegative()) {
            throw new DomainException("Opening balance cannot be negative");
        }
        this.id = id;
        this.balance = opening;
    }

    // The invariant lives WITH the data it protects.
    public void withdraw(Money amount) {
        if (amount.isNegativeOrZero()) {
            throw new DomainException("Withdrawal must be positive");
        }
        if (balance.isLessThan(amount)) {
            throw new InsufficientFundsException(id, balance, amount);
        }
        this.balance = balance.minus(amount);
    }

    public Money balance() { return balance; }
    public AccountId id() { return id; }
}

// Implements an inbound port; depends ONLY on outbound ports (interfaces).
public class TransferMoneyService implements TransferMoneyUseCase {
    private final LoadAccountPort loadAccount;   // outbound port
    private final SaveAccountPort saveAccount;   // outbound port
    private final AccountLock accountLock;

    public TransferMoneyService(LoadAccountPort loadAccount,
                                SaveAccountPort saveAccount,
                                AccountLock accountLock) {
        this.loadAccount = loadAccount;
        this.saveAccount = saveAccount;
        this.accountLock = accountLock;
    }

    @Override
    public void transfer(TransferCommand cmd) {
        Account source = loadAccount.load(cmd.sourceId());
        Account target = loadAccount.load(cmd.targetId());
        accountLock.lock(source.id());
        accountLock.lock(target.id());
        try {
            source.withdraw(cmd.amount());   // domain enforces the rule
            target.deposit(cmd.amount());
            saveAccount.save(source);
            saveAccount.save(target);
        } finally {
            accountLock.release(source.id());
            accountLock.release(target.id());
        }
    }
}

// Inbound port: the contract the outside world uses to drive the app.
public interface TransferMoneyUseCase {
    void transfer(TransferCommand cmd);
}

// Outbound ports: contracts the app needs the outside to fulfill.
public interface LoadAccountPort {
    Account load(AccountId id);   // returns a DOMAIN object, not a JPA entity
}
public interface SaveAccountPort {
    void save(Account account);
}
public interface AccountEventPublisher {
    void published(MoneyTransferred event);
}

@RestController
@RequestMapping("/api/transfers")
class TransferController {
    private final TransferMoneyUseCase transferMoney;  // inbound PORT, not the impl

    TransferController(TransferMoneyUseCase transferMoney) {
        this.transferMoney = transferMoney;
    }

    @PostMapping
    ResponseEntity<Void> transfer(@RequestBody @Valid TransferRequest req) {
        // INPUT validation (shape, ranges) lives here, at the edge.
        var cmd = new TransferCommand(
            new AccountId(req.sourceId()),
            new AccountId(req.targetId()),
            Money.of(req.amount(), req.currency()));
        transferMoney.transfer(cmd);          // hand off to the core
        return ResponseEntity.accepted().build();
    }
}

@Component
class AccountPersistenceAdapter implements LoadAccountPort, SaveAccountPort {
    private final AccountJpaRepository repo;   // Spring Data interface
    private final AccountMapper mapper;        // entity <-> domain

    AccountPersistenceAdapter(AccountJpaRepository repo, AccountMapper mapper) {
        this.repo = repo;
        this.mapper = mapper;
    }

    @Override
    public Account load(AccountId id) {
        AccountJpaEntity entity = repo.findById(id.value())
            .orElseThrow(() -> new AccountNotFoundException(id));
        return mapper.toDomain(entity);        // translate at the boundary
    }

    @Override
    public void save(Account account) {
        repo.save(mapper.toJpaEntity(account));
    }
}

// Transaction declared at the use-case boundary in a thin infrastructure wrapper,
// OR via @Transactional on the application service if you accept that one
// framework annotation. Purists wrap it; pragmatists annotate the service.
@Transactional
public void transfer(TransferCommand cmd) {
    Account source = loadAccount.load(cmd.sourceId());
    Account target = loadAccount.load(cmd.targetId());
    source.withdraw(cmd.amount());
    target.deposit(cmd.amount());
    saveAccount.save(source);   // both saves commit or roll back together
    saveAccount.save(target);
}

// Core owns this. It speaks money and intent, not Stripe or Adyen.
public interface PaymentGatewayPort {
    ChargeResult charge(ChargeRequest request);
    RefundResult refund(PaymentReference ref, Money amount);
}

public record ChargeRequest(
    Money amount, PaymentMethodToken token, IdempotencyKey key) {}

public record ChargeResult(
    PaymentReference reference, ChargeStatus status) {}

@Component
class StripePaymentAdapter implements PaymentGatewayPort {
    private final StripeClient stripe;
    @Override public ChargeResult charge(ChargeRequest req) {
        PaymentIntent intent = stripe.paymentIntents().create(
            PaymentIntentCreateParams.builder()
                .setAmount(req.amount().minorUnits())
                .setCurrency(req.amount().currency().code())
                .setPaymentMethod(req.token().value())
                .setIdempotencyKey(req.key().value())   // provider-specific detail
                .build());
        return new ChargeResult(
            new PaymentReference(intent.getId()), map(intent.getStatus()));
    }
    // refund(...) omitted
}

@Component
class AdyenPaymentAdapter implements PaymentGatewayPort {
    private final AdyenCheckout checkout;
    @Override public ChargeResult charge(ChargeRequest req) {
        var payment = checkout.payments(buildAdyenRequest(req));
        return new ChargeResult(
            new PaymentReference(payment.getPspReference()),
            map(payment.getResultCode()));
    }
    // refund(...) omitted
}

