// --- domain (no framework imports) ---
public final class Order {
    private final OrderId id;
    private final Money total;
    private OrderStatus status;

    private Order(OrderId id, Money total, OrderStatus status) {
        this.id = id; this.total = total; this.status = status;
    }

    // Factory enforces the invariant: the rule lives WITH the data.
    public static Order place(OrderId id, List<LineItem> items) {
        if (items.isEmpty()) throw new DomainException("Order must have items");
        Money total = items.stream().map(LineItem::subtotal)
            .reduce(Money.ZERO, Money::plus);
        OrderStatus status = total.isGreaterThan(Money.of(10_000))
            ? OrderStatus.PENDING_APPROVAL : OrderStatus.CONFIRMED;
        return new Order(id, total, status);
    }

    public boolean requiresPaymentNow() { return status == OrderStatus.CONFIRMED; }
    public OrderId id() { return id; }
    public Money total() { return total; }
    public OrderStatus status() { return status; }
}

// --- inbound port (defined by core, implemented by core) ---
public interface PlaceOrderUseCase {
    Order place(PlaceOrderCommand cmd);
}
public record PlaceOrderCommand(List<LineItem> items) {}

// --- outbound ports (defined by core, implemented by adapters) ---
public interface SaveOrderPort { void save(Order order); }
public interface ChargePaymentPort { void charge(OrderId id, Money amount); }
public interface OrderIdGenerator { OrderId next(); }

// --- application service (orchestrates, owns the transaction) ---
public class PlaceOrderService implements PlaceOrderUseCase {
    private final SaveOrderPort saveOrder;
    private final ChargePaymentPort chargePayment;
    private final OrderIdGenerator ids;

    public PlaceOrderService(SaveOrderPort saveOrder,
                             ChargePaymentPort chargePayment,
                             OrderIdGenerator ids) {
        this.saveOrder = saveOrder;
        this.chargePayment = chargePayment;
        this.ids = ids;
    }

    @Override
    @org.springframework.transaction.annotation.Transactional
    public Order place(PlaceOrderCommand cmd) {
        Order order = Order.place(ids.next(), cmd.items()); // domain decides status
        saveOrder.save(order);
        if (order.requiresPaymentNow()) {
            chargePayment.charge(order.id(), order.total());
        }
        return order;
    }
}

// --- inbound adapter ---
@org.springframework.web.bind.annotation.RestController
class OrderController {
    private final PlaceOrderUseCase placeOrder;
    OrderController(PlaceOrderUseCase placeOrder) { this.placeOrder = placeOrder; }

    @org.springframework.web.bind.annotation.PostMapping("/orders")
    OrderResponse create(@jakarta.validation.Valid @org.springframework.web.bind.annotation.RequestBody PlaceOrderRequest req) {
        Order order = placeOrder.place(new PlaceOrderCommand(req.toLineItems()));
        return OrderResponse.from(order);
    }
}

// --- outbound adapter ---
@org.springframework.stereotype.Component
class OrderPersistenceAdapter implements SaveOrderPort {
    private final OrderJpaRepository repo;
    private final OrderMapper mapper;
    OrderPersistenceAdapter(OrderJpaRepository repo, OrderMapper mapper) {
        this.repo = repo; this.mapper = mapper;
    }
    @Override public void save(Order order) { repo.save(mapper.toEntity(order)); }
}

// --- unit test: NO Spring, NO database ---
class PlaceOrderServiceTest {
    @org.junit.jupiter.api.Test
    void largeOrderIsPendingAndNotCharged() {
        var saved = new java.util.ArrayList<Order>();
        var charged = new java.util.ArrayList<Money>();
        var service = new PlaceOrderService(
            saved::add,                              // SaveOrderPort fake
            (id, amt) -> charged.add(amt),           // ChargePaymentPort fake
            () -> new OrderId("O-1"));               // id generator stub

        Order result = service.place(new PlaceOrderCommand(
            List.of(new LineItem("item", Money.of(20_000)))));

        org.junit.jupiter.api.Assertions.assertEquals(
            OrderStatus.PENDING_APPROVAL, result.status());
        org.junit.jupiter.api.Assertions.assertTrue(charged.isEmpty()); // not charged
        org.junit.jupiter.api.Assertions.assertEquals(1, saved.size());
    }
}

import com.tngtech.archunit.core.domain.JavaClasses;
import com.tngtech.archunit.core.importer.ClassFileImporter;
import com.tngtech.archunit.lang.ArchRule;
import org.junit.jupiter.api.BeforeAll;
import org.junit.jupiter.api.Test;

import static com.tngtech.archunit.lang.syntax.ArchRuleDefinition.noClasses;
import static com.tngtech.archunit.library.Architectures.layeredArchitecture;

class HexagonalArchitectureTest {

    private static JavaClasses classes;

    @BeforeAll
    static void importClasses() {
        // Exclude test classes so test fakes don't trip the rules.
        classes = new ClassFileImporter()
            .importPackages("com.shop");
    }

    @Test
    void domainMustNotDependOnFrameworks() {
        ArchRule rule = noClasses()
            .that().resideInAPackage("..domain..")
            .should().dependOnClassesThat()
            .resideInAnyPackage(
                "org.springframework..",
                "jakarta.persistence..",
                "javax.persistence..",
                "com.fasterxml.jackson..");
        rule.check(classes);
    }

    @Test
    void domainMustNotDependOnApplicationOrAdapters() {
        ArchRule rule = noClasses()
            .that().resideInAPackage("..domain..")
            .should().dependOnClassesThat()
            .resideInAnyPackage("..application..", "..adapter..");
        rule.check(classes);
    }

    @Test
    void adaptersMustReachCoreOnlyThroughPorts() {
        // Adapters may use ports + domain, but must not import application
        // service IMPLEMENTATIONS directly (those live in application.service).
        ArchRule rule = noClasses()
            .that().resideInAPackage("..adapter..")
            .should().dependOnClassesThat()
            .resideInAPackage("..application.service..");
        rule.check(classes);
    }

    @Test
    void enforceLayering() {
        ArchRule rule = layeredArchitecture().consideringOnlyDependenciesInLayers()
            .layer("Domain").definedBy("..domain..")
            .layer("Application").definedBy("..application..")
            .layer("AdapterIn").definedBy("..adapter.in..")
            .layer("AdapterOut").definedBy("..adapter.out..")
            // Domain is depended on by everyone, depends on no one.
            .whereLayer("Domain").mayOnlyBeAccessedByLayers(
                "Application", "AdapterIn", "AdapterOut")
            // Application is reached by adapters via inbound ports.
            .whereLayer("Application").mayOnlyBeAccessedByLayers(
                "AdapterIn", "AdapterOut")
            // Adapters are leaves: nobody depends on them.
            .whereLayer("AdapterIn").mayNotBeAccessedByAnyLayer()
            .whereLayer("AdapterOut").mayNotBeAccessedByAnyLayer();
        rule.check(classes);
    }
}
